CREATE FUNCTION example() RETURNS TRIGGER
LANGUAGE PLPGSQL
AS $$
DECLARE
  row_count INTEGER;
  column_name TEXT;
  table_name TEXT;
  schema_name TEXT;
  message_text TEXT;
BEGIN
  SELECT COUNT(*) INTO row_count FROM some_table;
  IF row_count > 0 THEN
    RAISE NOTICE 'rows: %', row_count;
  END IF;
  SELECT 'a', 'b', 'c'
    INTO column_name, table_name, schema_name;
  RETURN NEW;
END;
$$;

CREATE FUNCTION example() RETURNS void
LANGUAGE PLPGSQL
AS $$
DECLARE
  affected INTEGER;
  state TEXT;
BEGIN
  UPDATE some_table SET x = 1;
  GET DIAGNOSTICS affected = ROW_COUNT;
  GET STACKED DIAGNOSTICS state = RETURNED_SQLSTATE;
  RAISE NOTICE '%, %', affected, state;
END;
$$;

-- The rule only touches plpgsql bodies. A SQL function body's keyword
-- casing is not in scope here.
CREATE FUNCTION add_one(n integer) RETURNS integer AS $$
  select n + 1;
$$ LANGUAGE sql;

CREATE FUNCTION foo() RETURNS void AS $$
DECLARE
  user_count INTEGER;
BEGIN
  IF user_count IS NULL THEN
    RAISE NOTICE 'select from where stays alone';
  END IF;
  -- the comment also stays alone: select from where
END;
$$ LANGUAGE plpgsql;

